#include <stdio.h>
#include <string.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        char minutes[N][10];
        for (int i = 0; i < N; i++) {
            scanf("%s", minutes[i]);
        }
        int valid = 1;
        for (int i = 0; i < N - 1; i++) {
            if (strcmp(minutes[i], "cookie") == 0 && strcmp(minutes[i + 1], "milk") != 0) {
                valid = 0;
                break;
            }
        }
        if (valid && strcmp(minutes[N - 1], "cookie") != 0) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
    }
    return 0;
}

