import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            String[] minutes = new String[N];
            for (int i = 0; i < N; i++) {
                minutes[i] = scanner.next();
            }
            boolean valid = true;
            for (int i = 0; i < N - 1; i++) {
                if (minutes[i].equals("cookie") && !minutes[i + 1].equals("milk")) {
                    valid = false;
                    break;
                }
            }
            if (valid && !minutes[N - 1].equals("cookie")) {
                System.out.println("YES");
            } else {
                System.out.println("NO");
            }
        }
    }
}

